import { createContext, useReducer } from "react";
import { INITIAL_GAME_HISTORY_STATE } from "../constants/initial-state";
import { gameHistoryReducer } from "../reducers";

export const GameHistoryContext = createContext();

const GameHistoryProvider = ({ children }) => {
  const [state, dispatch] = useReducer(
    gameHistoryReducer,
    INITIAL_GAME_HISTORY_STATE
  );
  const { gameHistory, gameHistoryIndex } = state;

  return (
    <GameHistoryContext.Provider
      value={{ dispatch, gameHistory, gameHistoryIndex }}
    >
      {children}
    </GameHistoryContext.Provider>
  );
};

export default GameHistoryProvider;
