import { useContext } from "react";
import Modal from "react-modal";
import {
  ACTIVE_STRING,
  NON_EMPTY_TILES,
  UNAVAILABLE_STRING,
} from "../../constants/game";
import { BoardContext } from "../../contexts/BoardContext";
import { GameHistoryContext } from "../../contexts/GameHistoryContext";
import { WildcardsContext } from "../../contexts/WildcardsContext";
import {
  ADD_SNAPSHOT,
  CLOSE_MODAL,
  SET_ALL_WILDCARDS,
  SET_BOARD,
} from "../../types";
import {
  deselectAllTiles,
  replaceLetter,
  resetIds,
  solveBoard,
} from "../../utils/game";
import TileIcon from "../common/TileIcon";
import "./WildcardModal.css";

const customStyles = {
  content: {
    top: "50%",
    left: "50%",
    right: "auto",
    bottom: "auto",
    marginRight: "-50%",
    transform: "translate(-50%, -50%)",
  },
};

const WildcardModal = () => {
  const {
    modalOpen,
    board,
    dispatch: boardDispatch,
    totalScore,
  } = useContext(BoardContext);
  const { dispatch: gameHistoryDispatch } = useContext(GameHistoryContext);
  const {
    wildcards,
    dispatch: wildcardDispatch,
    letterToReplace,
  } = useContext(WildcardsContext);
  const { letter: originalLetter, columnIndex, rowIndex } = letterToReplace;

  const handleTileClick = (newTile) => {
    const updatedBoard = solveBoard(
      resetIds(
        deselectAllTiles(replaceLetter(board, columnIndex, rowIndex, newTile))
      )
    );

    const updatedWildcards = wildcards.map((wildcard) => {
      if (wildcard.status === ACTIVE_STRING) {
        return { ...wildcard, status: UNAVAILABLE_STRING };
      }
      return { ...wildcard };
    });

    boardDispatch({ type: SET_BOARD, payload: updatedBoard });
    boardDispatch({ type: CLOSE_MODAL });
    wildcardDispatch({
      type: SET_ALL_WILDCARDS,
      payload: updatedWildcards,
    });
    gameHistoryDispatch({
      type: ADD_SNAPSHOT,
      payload: {
        board: updatedBoard,
        wildcards: updatedWildcards,
        score: totalScore,
      },
    });
  };

  return (
    <Modal
      isOpen={modalOpen}
      style={customStyles}
      shouldCloseOnOverlayClick
      onRequestClose={() => {
        boardDispatch({ type: CLOSE_MODAL });
      }}
    >
      <div
        className="close-button"
        onClick={() => {
          boardDispatch({ type: CLOSE_MODAL });
        }}
      >
        ×
      </div>
      <h4>Replace with...</h4>
      <div className="letter-container">
        {NON_EMPTY_TILES.filter(({ letter }) => letter !== originalLetter).map(
          (tile, index) => (
            <TileIcon
              background={tile.defaultColor}
              letter={tile.letter}
              handleTileClick={() => handleTileClick(tile)}
              key={index}
              className="wildcard-icon"
            />
          )
        )}
      </div>
    </Modal>
  );
};

export default WildcardModal;
