import { useContext } from "react";
import { ImMagicWand } from "react-icons/im";
import {
  ACTIVE_STRING,
  AVAILABLE_STRING,
  UNAVAILABLE_STRING,
  WILDCARD_ACTIVE_STYLES,
  WILDCARD_AVAILABLE_STYLES,
  WILDCARD_STRING,
  WILDCARD_UNAVAILABLE_STYLES,
} from "../../constants/game";
import { WildcardsContext } from "../../contexts/WildcardsContext";
import { SET_WILDCARD_ACTIVE, SET_WILDCARD_AVAILABLE } from "../../types";

const Wildcard = ({ status, index }) => {
  const { dispatch } = useContext(WildcardsContext);

  const wildcardStyles =
    status === AVAILABLE_STRING
      ? WILDCARD_AVAILABLE_STYLES
      : status === UNAVAILABLE_STRING
      ? WILDCARD_UNAVAILABLE_STYLES
      : WILDCARD_ACTIVE_STYLES;

  const handleWildcardClick = () => {
    if (status === ACTIVE_STRING) {
      dispatch({ type: SET_WILDCARD_AVAILABLE, payload: index });
    } else if (status === AVAILABLE_STRING) {
      dispatch({ type: SET_WILDCARD_ACTIVE, payload: index });
    }
  };

  return (
    <ImMagicWand
      {...wildcardStyles}
      onClick={handleWildcardClick}
      title={WILDCARD_STRING}
      className="wildcard"
    />
  );
};

export default Wildcard;
