import { createContext, useContext } from "react";
import { NUM_COLUMNS, NUM_ROWS, TILES } from "../constants/game";
import {
  DECREMENT_HISTORY_INDEX,
  INCREMENT_HISTORY_INDEX,
  RESET_BOARD,
  RESET_GAME_HISTORY,
  RESET_WILDCARDS,
  SET_ALL_WILDCARDS,
  SET_BOARD,
  SET_SCORE,
} from "../types";
import { createBoard, solveBoard } from "../utils/game";
import { BoardContext } from "./BoardContext";
import { GameHistoryContext } from "./GameHistoryContext";
import { WildcardsContext } from "./WildcardsContext";

export const ControlsContext = createContext();

const ControlsProvider = ({ children }) => {
  const {
    gameHistory,
    gameHistoryIndex,
    dispatch: gameHistoryDispatch,
  } = useContext(GameHistoryContext);
  const { dispatch: boardDispatch } = useContext(BoardContext);
  const { dispatch: wildcardDispatch } = useContext(WildcardsContext);

  const handleUndo = () => {
    if (gameHistoryIndex === 0) {
      return;
    }
    const previousHistoryIndex = gameHistoryIndex - 1;
    const {
      board: previousBoard,
      score: previousScore,
      wildcards: previousWildcards,
    } = gameHistory[previousHistoryIndex];
    boardDispatch({ type: SET_BOARD, payload: previousBoard });
    boardDispatch({ type: SET_SCORE, payload: previousScore });
    wildcardDispatch({ type: SET_ALL_WILDCARDS, payload: previousWildcards });
    gameHistoryDispatch({ type: DECREMENT_HISTORY_INDEX });
  };

  const handleRedo = () => {
    if (gameHistoryIndex === gameHistory.length - 1) {
      return;
    }
    const subsequentHistoryIndex = gameHistoryIndex + 1;
    const {
      board: subsequentBoard,
      score: subsequentScore,
      wildcards: subsequentWildcards,
    } = gameHistory[subsequentHistoryIndex];
    boardDispatch({ type: SET_BOARD, payload: subsequentBoard });
    boardDispatch({ type: SET_SCORE, payload: subsequentScore });
    wildcardDispatch({ type: SET_ALL_WILDCARDS, payload: subsequentWildcards });
    gameHistoryDispatch({ type: INCREMENT_HISTORY_INDEX });
  };

  const startNewGame = () => {
    const newBoard = solveBoard(createBoard(NUM_ROWS, NUM_COLUMNS, TILES));
    boardDispatch({ type: RESET_BOARD, payload: newBoard });
    wildcardDispatch({ type: RESET_WILDCARDS });
    gameHistoryDispatch({ type: RESET_GAME_HISTORY, payload: newBoard });
  };

  return (
    <ControlsContext.Provider value={{ handleUndo, handleRedo, startNewGame }}>
      {children}
    </ControlsContext.Provider>
  );
};

export default ControlsProvider;
