import { useContext } from "react";
import "./App.css";
import Board from "./components/main/Board";
import Footer from "./components/main/Footer";
import Header from "./components/main/Header";
import { LETTER_G, LETTER_Z } from "./constants/game";
import { ControlsContext } from "./contexts/ControlsContext";

const App = () => {
  const { handleUndo, handleRedo, startNewGame } = useContext(ControlsContext);

  return (
    <div
      className="game-container custom-cursor"
      onKeyDown={(event) => {
        if (event.key === LETTER_Z && event.metaKey && !event.shiftKey) {
          event.preventDefault();
          handleUndo();
        }

        if (event.key === LETTER_Z && event.metaKey && event.shiftKey) {
          event.preventDefault();
          handleRedo();
        }

        if (event.key === LETTER_G && event.metaKey) {
          event.preventDefault();
          startNewGame();
        }
      }}
      tabIndex={1}
    >
      <Header />
      <Board />
      <Footer />
    </div>
  );
};

export default App;
