import { useContext } from "react";
import { BoardContext } from "../../contexts/BoardContext";
import { formatScore } from "../../utils/game";
import HighScore from "./HighScore";
import "./Score.css";

const Score = () => {
  const { numSelected, selectedScore, totalScore } = useContext(BoardContext);

  return (
    <div className="score-container">
      <div>
        <span className="heading">Selected: </span>
        {formatScore(selectedScore)} {numSelected && `(${numSelected} tiles)`}
      </div>
      <div>
        <span className="heading">Total: </span>
        {formatScore(totalScore)}
      </div>
      <HighScore />
    </div>
  );
};

export default Score;
