import { INITIAL_BOARD_STATE } from "../constants/initial-state";
import {
  CLOSE_MODAL,
  OPEN_MODAL,
  RESET_BOARD,
  SET_BOARD,
  SET_SCORE,
  SET_SELECTION,
  SET_TILE_COUNT,
} from "../types";
import { countTiles } from "../utils/game";

export const boardReducer = (state, action) => {
  switch (action.type) {
    case SET_BOARD:
      return { ...state, board: action.payload };
    case SET_SCORE:
      return { ...state, totalScore: action.payload };
    case SET_TILE_COUNT:
      return { ...state, tileCount: action.payload };
    case SET_SELECTION:
      return { ...state, selection: action.payload };
    case OPEN_MODAL:
      return { ...state, modalOpen: true };
    case CLOSE_MODAL:
      return { ...state, modalOpen: false };
    case RESET_BOARD: {
      return {
        ...INITIAL_BOARD_STATE,
        board: action.payload,
        initialTileCount: countTiles(action.payload),
        tileCount: countTiles(action.payload),
      };
    }
    default:
      return state;
  }
};
