import { useContext, useState, useEffect } from "react";
import { BiUndo, BiRedo } from "react-icons/bi";
import {
  REDO_BUTTON_TOOLTIP,
  UNDO_REDO_DISABLED_STYLES,
  UNDO_REDO_ENABLED_STYLES,
  UNDO_BUTTON_TOOLTIP,
} from "../../constants/game";
import { GameHistoryContext } from "../../contexts/GameHistoryContext";
import { ControlsContext } from "../../contexts/ControlsContext";
import "./Footer.css";

const Controls = () => {
  const [undoStyles, setUndoStyles] = useState(UNDO_REDO_DISABLED_STYLES);
  const [redoStyles, setRedoStyles] = useState(UNDO_REDO_DISABLED_STYLES);
  const { handleUndo, handleRedo } = useContext(ControlsContext);

  const { gameHistory, gameHistoryIndex } = useContext(GameHistoryContext);

  useEffect(() => {
    if (gameHistoryIndex === 0) {
      setUndoStyles(UNDO_REDO_DISABLED_STYLES);
    }

    if (gameHistoryIndex >= 1) {
      setUndoStyles(UNDO_REDO_ENABLED_STYLES);
    }

    if (gameHistory.length > 1 && gameHistoryIndex < gameHistory.length - 1) {
      setRedoStyles(UNDO_REDO_ENABLED_STYLES);
    }

    if (gameHistoryIndex === gameHistory.length - 1) {
      setRedoStyles(UNDO_REDO_DISABLED_STYLES);
    }
  }, [gameHistoryIndex, gameHistory]);

  return (
    <div className="controls">
      <BiUndo
        onClick={handleUndo}
        title={UNDO_BUTTON_TOOLTIP}
        {...undoStyles}
      />
      <BiRedo
        onClick={handleRedo}
        title={REDO_BUTTON_TOOLTIP}
        {...redoStyles}
      />
    </div>
  );
};

export default Controls;
