import { createContext, useEffect, useReducer } from "react";
import { wildcardReducer } from "../reducers";
import { SOME_WILDCARD_ACTIVE, NO_WILDCARD_ACTIVE } from "../types";
import { ACTIVE_STRING } from "../constants/game";
import { INITIAL_WILDCARDS_STATE } from "../constants/initial-state";

export const WildcardsContext = createContext();

const WildcardsProvider = ({ children }) => {
  const [state, dispatch] = useReducer(
    wildcardReducer,
    INITIAL_WILDCARDS_STATE
  );
  const { wildcards, wildcardActive, letterToReplace } = state;

  useEffect(() => {
    if (wildcards.some((wildcard) => wildcard.status === ACTIVE_STRING)) {
      dispatch({ type: SOME_WILDCARD_ACTIVE });
    } else if (
      wildcards.every((wildcard) => wildcard.status !== ACTIVE_STRING)
    ) {
      dispatch({ type: NO_WILDCARD_ACTIVE });
    }
  }, [wildcards]);

  return (
    <WildcardsContext.Provider
      value={{ wildcards, wildcardActive, letterToReplace, dispatch }}
    >
      {children}
    </WildcardsContext.Provider>
  );
};

export default WildcardsProvider;
