import { useState, useEffect, useContext } from "react";
import { HIGH_SCORE_STRING } from "../../constants/game";
import { BoardContext } from "../../contexts/BoardContext";
import { formatScore } from "../../utils/game";
import "./Score.css";

const HighScore = () => {
  const { totalScore } = useContext(BoardContext);
  const [highScore, setHighScore] = useState(
    window.localStorage.getItem(HIGH_SCORE_STRING) || 0
  );

  useEffect(() => {
    if (totalScore > highScore) {
      setHighScore(totalScore);
      window.localStorage.setItem(HIGH_SCORE_STRING, totalScore);
    }
  }, [totalScore, highScore]);

  return (
    <div>
      <span className="heading">High score: </span> {formatScore(highScore)}
    </div>
  );
};

export default HighScore;
