import {
  SET_WILDCARD_ACTIVE,
  SET_WILDCARD_AVAILABLE,
  SOME_WILDCARD_ACTIVE,
  NO_WILDCARD_ACTIVE,
  SET_LETTER_TO_REPLACE,
  SET_ALL_WILDCARDS,
  RESET_WILDCARDS,
} from "../types";
import { ACTIVE_STRING, AVAILABLE_STRING } from "../constants/game";
import { INITIAL_WILDCARDS_STATE } from "../constants/initial-state";

export const wildcardReducer = (state, action) => {
  switch (action.type) {
    case SET_WILDCARD_ACTIVE:
      return {
        ...state,
        wildcards: [
          ...state.wildcards.map((wildcard, index) => {
            if (wildcard.status === ACTIVE_STRING) {
              return { ...wildcard, status: AVAILABLE_STRING };
            }
            if (index === action.payload) {
              return { ...wildcard, status: ACTIVE_STRING };
            }
            return { ...wildcard };
          }),
        ],
      };
    case SET_WILDCARD_AVAILABLE:
      return {
        ...state,
        wildcards: [
          ...state.wildcards.map((wildcard, index) => {
            if (index === action.payload) {
              return { ...wildcard, status: AVAILABLE_STRING };
            }
            return { ...wildcard };
          }),
        ],
      };
    case SET_ALL_WILDCARDS:
      return { ...state, wildcards: action.payload };
    case SOME_WILDCARD_ACTIVE:
      return { ...state, wildcardActive: true };
    case NO_WILDCARD_ACTIVE:
      return { ...state, wildcardActive: false };
    case SET_LETTER_TO_REPLACE:
      return {
        ...state,
        letterToReplace: {
          letter: action.payload.letter,
          rowIndex: action.payload.rowIndex,
          columnIndex: action.payload.columnIndex,
        },
      };
    case RESET_WILDCARDS:
      return INITIAL_WILDCARDS_STATE;
    default:
      return state;
  }
};
