import {
  ADD_SNAPSHOT,
  DECREMENT_HISTORY_INDEX,
  INCREMENT_HISTORY_INDEX,
  RESET_GAME_HISTORY,
} from "../types";
import { INITIAL_GAME_HISTORY_STATE } from "../constants/initial-state";

export const gameHistoryReducer = (state, action) => {
  switch (action.type) {
    case ADD_SNAPSHOT:
      return {
        ...state,
        gameHistory: [
          ...state.gameHistory.slice(0, state.gameHistoryIndex + 1),
          action.payload,
        ],
        gameHistoryIndex: state.gameHistoryIndex + 1,
      };
    case DECREMENT_HISTORY_INDEX:
      return { ...state, gameHistoryIndex: state.gameHistoryIndex - 1 };
    case INCREMENT_HISTORY_INDEX:
      return { ...state, gameHistoryIndex: state.gameHistoryIndex + 1 };
    case RESET_GAME_HISTORY:
      return {
        ...INITIAL_GAME_HISTORY_STATE,
        gameHistory: [
          {
            ...INITIAL_GAME_HISTORY_STATE.gameHistory[0],
            board: action.payload,
          },
        ],
      };
    default:
      return state;
  }
};
