const _ = require("lodash");
const { v4: uuidv4 } = require("uuid");

export const createBoard = (numRows, numColumns, tiles) => {
  const nonEmptyTiles = tiles.filter((tile) => tile.letter);
  const numTiles = numRows * numColumns;
  const unshuffledBoard = [];

  for (let i = 0; i < numTiles; i++) {
    const { letter, defaultColor, colorIfSelected } =
      nonEmptyTiles[Math.floor(Math.random() * nonEmptyTiles.length)];
    unshuffledBoard.push({
      letter,
      defaultColor,
      colorIfSelected,
      hasAdjacent: false,
      isSelected: false,
    });
  }

  return _.chunk(_.shuffle(unshuffledBoard), numRows);
};

// board looks like: [[{letter: ''},...], ...]
export const solveBoard = (board) => {
  const numColumns = board.length;
  const numRows = board[0]?.length;

  for (let column = 0; column < numColumns; column++) {
    for (let row = 0; row < numRows; row++) {
      const currentTile = board[column][row];
      if (currentTile.id || !currentTile.letter) {
        continue;
      }

      const queue = [[column, row]];

      while (queue.length) {
        const [scannedColumn, scannedRow] = queue[0];

        const tileBeingScanned = board[scannedColumn][scannedRow];

        if (!tileBeingScanned.id) {
          tileBeingScanned.id = uuidv4();
        }

        const tileToTop = [scannedColumn - 1, scannedRow];
        const tileToRight = [scannedColumn, scannedRow + 1];
        const tileToBottom = [scannedColumn + 1, scannedRow];
        const tileToLeft = [scannedColumn, scannedRow - 1];
        const adjacentTiles = [
          tileToTop,
          tileToRight,
          tileToBottom,
          tileToLeft,
        ];

        adjacentTiles.forEach(([adjacentTileColumn, adjacentTileRow]) => {
          const tile = board[adjacentTileColumn]?.[adjacentTileRow];
          if (tile && !tile.id && tile.letter === tileBeingScanned.letter) {
            tile.id = tileBeingScanned.id;
            tileBeingScanned.hasAdjacent = true;
            tile.hasAdjacent = true;
            queue.push([adjacentTileColumn, adjacentTileRow]);
          }
        });

        queue.shift();
      }
    }
  }

  return board;
};

export const selectTiles = (board, id) => {
  return board.map((column) => {
    return column.map((tile) => ({
      ...tile,
      isSelected: tile.id === id,
    }));
  });
};

export const deselectAllTiles = (board) => {
  return board.map((column) => {
    return column.map((tile) => ({
      ...tile,
      isSelected: false,
    }));
  });
};

const cascadeRows = (board) => {
  board.forEach((column) => {
    column.forEach((tile, index) => {
      if (tile.letter === "") {
        column.splice(index, 1);
        column.unshift({ letter: "", defaultColor: "", colorIfSelected: "" });
      }
    });
  });
};

const cascadeColumns = (board) => {
  while (board.some((column) => column.every((tile) => tile.letter === ""))) {
    board.forEach((column, index) => {
      if (column.every((tile) => tile.letter === "")) {
        board.splice(index, 1);
      }
    });
  }
};

export const clearTiles = (board) => {
  const numColumns = board.length;
  const numRows = board[0]?.length;

  for (let column = 0; column < numColumns; column++) {
    for (let row = 0; row < numRows; row++) {
      const currentTile = board[column][row];
      currentTile.id = "";
      currentTile.hasAdjacent = false;
      if (currentTile.isSelected) {
        currentTile.letter = "";
      }
    }
  }

  cascadeRows(board);
  cascadeColumns(board);

  return board;
};

export const calculateScore = (board) => {
  const numColumns = board.length;
  const numRows = board[0]?.length;

  let numSelected = 0;
  for (let column = 0; column < numColumns; column++) {
    for (let row = 0; row < numRows; row++) {
      if (board[column][row].isSelected) {
        numSelected++;
      }
    }
  }

  if (!numSelected) {
    return 0;
  }

  return { numSelected, selectedScore: (numSelected - 1) ** 2 };
};

export const countTiles = (board) => {
  const numColumns = board.length;
  const numRows = board[0]?.length;

  const count = {};
  for (let column = 0; column < numColumns; column++) {
    for (let row = 0; row < numRows; row++) {
      const { letter } = board[column][row];
      if (letter) {
        if (count[letter]) {
          count[letter]++;
        } else {
          count[letter] = 1;
        }
      }
    }
  }

  return count;
};

export const formatScore = (score) => {
  if (score && score >= 1000) {
    score = score.toString();
    const leadingDigits = score.slice(0, score.length - 3);
    const hundredsDigits = score.slice(score.length - 3);
    return `${leadingDigits},${hundredsDigits}`;
  } else {
    return score;
  }
};

export const resetIds = (board) => {
  return board.map((column) => column.map((tile) => ({ ...tile, id: "" })));
};

export const replaceLetter = (board, columnIndex, rowIndex, newLetter) => {
  const copyOfColumn = [...board[columnIndex]];
  const updatedColumn = [
    ...copyOfColumn.slice(0, rowIndex),
    newLetter,
    ...copyOfColumn.slice(rowIndex + 1),
  ];
  return [
    ...board.slice(0, columnIndex),
    updatedColumn,
    ...board.slice(columnIndex + 1),
  ];
};
