import { useState, useEffect, useContext } from "react";
import PropTypes from "prop-types";
import {
  BLACK_STRING,
  DEFAULT_BORDER,
  EMPTY_BORDER,
  POINTER_STRING,
  SELECTED_BORDER,
  WHITE_STRING,
} from "../../constants/game";
import { BoardContext } from "../../contexts/BoardContext";
import {
  clearTiles,
  deselectAllTiles,
  selectTiles,
  solveBoard,
} from "../../utils/game";
import "./Tile.css";
import { WildcardsContext } from "../../contexts/WildcardsContext";
import {
  ADD_SNAPSHOT,
  OPEN_MODAL,
  SET_BOARD,
  SET_LETTER_TO_REPLACE,
  SET_SCORE,
} from "../../types";
import { GameHistoryContext } from "../../contexts/GameHistoryContext";

const Tile = ({
  letter,
  defaultColor,
  colorIfSelected,
  hasAdjacent,
  isSelected,
  id,
  columnIndex,
  rowIndex,
}) => {
  const [backgroundColor, setBackgroundColor] = useState(defaultColor);
  const [fontColor, setFontColor] = useState(BLACK_STRING);
  const [border, setBorder] = useState(letter ? DEFAULT_BORDER : EMPTY_BORDER);
  const {
    board,
    totalScore,
    selectedScore,
    dispatch: boardDispatch,
  } = useContext(BoardContext);

  const {
    wildcards,
    wildcardActive,
    dispatch: wildcardDispatch,
  } = useContext(WildcardsContext);

  const { dispatch: gameHistoryDispatch } = useContext(GameHistoryContext);

  useEffect(() => {
    if (letter && isSelected) {
      setBackgroundColor(colorIfSelected);
      setFontColor(WHITE_STRING);
      setBorder(SELECTED_BORDER);
    } else {
      setBackgroundColor(defaultColor);
      setFontColor(BLACK_STRING);
      setBorder(letter ? DEFAULT_BORDER : EMPTY_BORDER);
    }
  }, [isSelected, colorIfSelected, defaultColor, letter]);

  const handleTileClick = () => {
    if (wildcardActive) {
      boardDispatch({ type: OPEN_MODAL });
      wildcardDispatch({
        type: SET_LETTER_TO_REPLACE,
        payload: { letter, rowIndex, columnIndex },
      });
    } else if (letter && hasAdjacent) {
      if (!isSelected) {
        boardDispatch({ type: SET_BOARD, payload: selectTiles(board, id) });
      } else {
        const updatedScore = totalScore + selectedScore;
        const updatedBoard = solveBoard(deselectAllTiles(clearTiles(board)));

        boardDispatch({ type: SET_BOARD, payload: updatedBoard });
        boardDispatch({ type: SET_SCORE, payload: updatedScore });

        gameHistoryDispatch({
          type: ADD_SNAPSHOT,
          payload: { board: updatedBoard, score: updatedScore, wildcards },
        });
      }
    }
  };

  return (
    <div
      style={{
        backgroundColor,
        border,
        cursor: !wildcardActive && letter && hasAdjacent && POINTER_STRING,
        color: fontColor,
      }}
      className={`tile ${wildcardActive && "wildcard-cursor"}`}
      onClick={handleTileClick}
    >
      <div>{letter}</div>
    </div>
  );
};

Tile.propTypes = {
  letter: PropTypes.string,
  defaultColor: PropTypes.string,
  colorIfSelected: PropTypes.string,
  hasAdjacent: PropTypes.bool,
  isSelected: PropTypes.bool,
  id: PropTypes.string,
};

Tile.defaultProps = {
  letter: "",
  defaultColor: "",
  colorIfSelected: "",
  hasAdjacent: false,
  isSelected: false,
  id: null,
};

export default Tile;
