import { useContext } from "react";
import { TILES } from "../../constants/game";
import { BoardContext } from "../../contexts/BoardContext";
import TileIcon from "../common/TileIcon";
import "./Count.css";

const Count = () => {
  const { initialTileCount, tileCount } = useContext(BoardContext);
  const tileCountArray = Object.entries(tileCount).sort();

  return (
    <div className="count-container">
      {tileCountArray.map(([letter, count]) => {
        const tileBackground = TILES.filter((tile) => tile.letter === letter)[0]
          .defaultColor;

        return (
          <div key={letter} className="individual-container">
            <TileIcon
              letter={letter}
              background={tileBackground}
              className="legend"
            />
            <div className="count-text">
              {count} / {initialTileCount[letter]}
            </div>
          </div>
        );
      })}
    </div>
  );
};

export default Count;
