import { createContext, useEffect, useReducer } from "react";
import { INITIAL_BOARD_STATE } from "../constants/initial-state";
import { boardReducer } from "../reducers/";
import { SET_SELECTION, SET_TILE_COUNT } from "../types";
import { calculateScore, countTiles } from "../utils/game";

export const BoardContext = createContext();

const BoardProvider = ({ children }) => {
  const [state, dispatch] = useReducer(boardReducer, INITIAL_BOARD_STATE);
  const {
    board,
    totalScore,
    initialTileCount,
    tileCount,
    modalOpen,
    selection,
  } = state;
  const { numSelected, selectedScore } = selection;

  useEffect(() => {
    dispatch({ type: SET_TILE_COUNT, payload: countTiles(board) });
    dispatch({ type: SET_SELECTION, payload: calculateScore(board) });
  }, [board]);

  return (
    <BoardContext.Provider
      value={{
        board,
        totalScore,
        numSelected,
        selectedScore,
        initialTileCount,
        tileCount,
        dispatch,
        modalOpen,
      }}
    >
      {children}
    </BoardContext.Provider>
  );
};

export default BoardProvider;
