import { useContext } from "react";
import { WildcardsContext } from "../../contexts/WildcardsContext";
import Wildcard from "./Wildcard";
import "./Footer.css";

const Wildcards = () => {
  const { wildcards } = useContext(WildcardsContext);

  return (
    <div className="wildcards">
      {wildcards.map(({ status }, index) => (
        <Wildcard status={status} index={index} key={index} />
      ))}
    </div>
  );
};

export default Wildcards;
